import { render, screen } from '@testing-library/react-native';
import ProductCard from '../ProductCard';

test('affiche le nom et le prix du produit', () => {
  const product = { name: 'Smartphone', price: 29900, image: 'url', isPromo: false };
  render(<ProductCard product={product} onAddToCart={jest.fn()} />);

  expect(screen.getByTestId('product-name')).toHaveTextContent('Smartphone');
  expect(screen.getByTestId('product-price')).toHaveTextContent('29900 FCFA');
});
