test('affiche le badge promo uniquement si le produit est en promotion', () => {
  const promoProduct = { name: 'Smartphone', price: 29900, image: 'url', isPromo: true };
  const { rerender } = render(<ProductCard product={promoProduct} onAddToCart={jest.fn()} />);
  expect(screen.getByTestId('promo-badge')).toBeTruthy();

  const normalProduct = { ...promoProduct, isPromo: false };
  rerender(<ProductCard product={normalProduct} onAddToCart={jest.fn()} />);
  expect(screen.queryByTestId('promo-badge')).toBeNull();
});
```

