```javascript
import { useCartStore } from '../store/cartStore';

// Reset du store avant chaque test
beforeEach(() => {
  useCartStore.setState({ items: [] });
});

test('addItem ajoute un nouvel article au panier', () => {
  const { addItem, items, getItemCount } = useCartStore.getState();
  const newItem = { id: '1', name: 'Produit A', price: 1000, quantity: 2 };

  addItem(newItem);

  expect(useCartStore.getState().items).toHaveLength(1);
  expect(useCartStore.getState().items[0]).toEqual(newItem);
  expect(useCartStore.getState().getItemCount()).toBe(2);
});
```

```javascript
test('addItem additionne les quantités si le produit existe déjà', () => {
  const { addItem } = useCartStore.getState();
  const item = { id: '1', name: 'Produit A', price: 1000, quantity: 1 };

  addItem(item);
  addItem({ ...item, quantity: 3 });

  const items = useCartStore.getState().items;
  expect(items).toHaveLength(1);
  expect(items[0].quantity).toBe(4);
  expect(useCartStore.getState().getTotalPrice()).toBe(4000);
});
```

```javascript
test('removeItem supprime un article du panier', () => {
  const { addItem, removeItem } = useCartStore.getState();
  addItem({ id: '1', name: 'Produit A', price: 1000, quantity: 1 });
  addItem({ id: '2', name: 'Produit B', price: 2000, quantity: 1 });

  removeItem('1');
  expect(useCartStore.getState().items).toHaveLength(1);
  expect(useCartStore.getState().items[0].id).toBe('2');
});

test('updateQuantity modifie la quantité d'un article', () => {
  const { addItem, updateQuantity } = useCartStore.getState();
  addItem({ id: '1', name: 'Produit A', price: 1000, quantity: 1 });

  updateQuantity('1', 5);
  expect(useCartStore.getState().items[0].quantity).toBe(5);
  expect(useCartStore.getState().getTotalPrice()).toBe(5000);
});

test('clearCart vide complètement le panier', () => {
  const { addItem, clearCart } = useCartStore.getState();
  addItem({ id: '1', name: 'Produit A', price: 1000, quantity: 1 });

  clearCart();
  expect(useCartStore.getState().items).toHaveLength(0);
  expect(useCartStore.getState().getItemCount()).toBe(0);
});
```

